<span class="line">    <span class="token keyword">elif</span> <span class="token builtin">isinstance</span><span class="token punctuation">(</span>node<span class="token punctuation">,</span> yaml<span class="token punctuation">.</span>SequenceNode<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
